using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed the discriminator property from "Discriminator" to "$type".
            // Preserve the old name so existing 500K documents remain readable and
            // direct SQL queries referencing c.Discriminator keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed the id format from "EntityType|KeyValue" to just "KeyValue".
            // Preserve the old format so existing documents are still addressable.
            entity.HasKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonProperty("id");
            entity.UseETagConcurrency();
        });

        // HasIndex is no longer supported on the Cosmos provider in EF Core 9
        // (Cosmos manages its own indexes). The previous call has been removed.
    }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Opt back into the EF8 id-format ("Product|123") so existing documents match.
        // Without this, EF9 generates bare key values and cannot find old rows.
        optionsBuilder.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "ProductsDb",
            cosmosOptions => { });

        base.OnConfiguring(optionsBuilder);
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } = string.Empty; }

